import ast, sys

# 检查所有 src/*.py 文件的未使用 import
src_files = [
    'src/agent.py', 'src/cli.py', 'src/models.py', 'src/tools.py',
    'src/prompt.py', 'src/providers.py', 'src/memory.py', 'src/skills.py',
    'src/git.py', 'src/logger.py', 'src/mcp_client.py', 'src/colors.py',
]

for filepath in src_files:
    with open(filepath) as f:
        source = f.read()
    try:
        tree = ast.parse(source)
    except SyntaxError as e:
        print(f'{filepath}: SyntaxError: {e}')
        continue

    # 收集所有 import 的名称
    imports = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                name = alias.asname or alias.name
                imports[name] = node.lineno
        elif isinstance(node, ast.ImportFrom):
            for alias in node.names:
                name = alias.asname or alias.name
                imports[name] = node.lineno

    # 收集所有被使用的名称
    used_names = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Name):
            used_names.add(node.id)
        elif isinstance(node, ast.Attribute):
            if isinstance(node.value, ast.Name):
                used_names.add(node.value.id)

    # 排除 __all__ 导出
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == '__all__':
                    pass

    # 检查未使用的 import
    for name, lineno in sorted(imports.items(), key=lambda x: x[1]):
        if name not in used_names and name != '*':
            print(f'{filepath}:{lineno}: unused import: {name}')
"

